from __future__ import annotations

import argparse
import os
import subprocess
import sys
from pathlib import Path
from textwrap import dedent


GUIDE = dedent(
    """
    Python Dependency Lock File Best Practices

    Goal
    ----
    Ensure consistent dependency versions in development, testing, and production by
    pinning exact versions and, where possible, verifying package hashes.

    Supported workflows
    -------------------
    1) pip + requirements.txt with hashes
    2) Poetry + poetry.lock

    1. pip workflow
    ---------------
    Recommended file layout:
      - requirements.in      : top-level direct dependencies
      - requirements.txt     : fully pinned lock file with hashes
      - dev-requirements.in   : development dependencies
      - dev-requirements.txt  : fully pinned dev lock file with hashes

    Typical generation flow:
      pip install pip-tools
      pip-compile --generate-hashes -o requirements.txt requirements.in
      pip-compile --generate-hashes -o dev-requirements.txt dev-requirements.in

    Install in production:
      pip install --require-hashes -r requirements.txt

    Update a single package:
      pip-compile --upgrade-package package_name --generate-hashes -o requirements.txt requirements.in

    Update all packages:
      pip-compile --upgrade --generate-hashes -o requirements.txt requirements.in

    Notes:
      - Commit requirements.in and requirements.txt to version control.
      - Never hand-edit requirements.txt if it is generated.
      - Use --require-hashes in CI/production to prevent tampering and ensure reproducibility.
      - If you need platform-specific dependencies, generate lock files per environment or use markers carefully.

    2. Poetry workflow
    ------------------
    Recommended files:
      - pyproject.toml : direct dependency declarations
      - poetry.lock    : resolved and locked dependency graph

    Typical generation flow:
      poetry lock
      poetry install

    Update all dependencies:
      poetry update

    Update one dependency:
      poetry update package_name

    Notes:
      - Commit both pyproject.toml and poetry.lock.
      - Do not edit poetry.lock manually.
      - Run installs with the same Poetry version when possible to reduce churn.
      - In CI, use `poetry install --no-interaction --no-ansi`.

    General best practices
    ----------------------
    - Pin versions for applications; use a lock file for exact reproducibility.
    - Separate direct dependencies from transitive locks.
    - Review dependency updates regularly instead of allowing drift.
    - Use automated dependency update tools (e.g., Dependabot, Renovate).
    - Rebuild and test after every lock file update.
    - Keep production and CI installs identical to local developer installs where possible.

    Suggested team policy
    ---------------------
    - A change to dependencies must include an updated lock file.
    - Lock file updates should be tested in CI.
    - Production deploys must install from committed lock files only.
    - For pip, production installs must use `--require-hashes`.
    - For Poetry, production installs must use the committed `poetry.lock`.

    """
).strip()


def run(cmd: list[str], cwd: Path | None = None) -> int:
    try:
        proc = subprocess.run(cmd, cwd=cwd, check=False)
        return proc.returncode
    except FileNotFoundError as e:
        print(f"Command not found: {cmd[0]}", file=sys.stderr)
        return 127


def find_project_root(start: Path) -> Path:
    candidates = [
        "pyproject.toml",
        "requirements.in",
        "requirements.txt",
        "poetry.lock",
    ]
    cur = start.resolve()
    for _ in range(8):
        if any((cur / c).exists() for c in candidates):
            return cur
        if cur.parent == cur:
            break
        cur = cur.parent
    return start.resolve()


def has_poetry_project(root: Path) -> bool:
    return (root / "pyproject.toml").exists() and (root / "poetry.lock").exists()


def has_piptools_project(root: Path) -> bool:
    return (root / "requirements.in").exists() or (root / "dev-requirements.in").exists()


def status(root: Path) -> int:
    lines = []
    lines.append(f"Project root: {root}")
    if (root / "pyproject.toml").exists():
        lines.append("pyproject.toml: present")
    if (root / "poetry.lock").exists():
        lines.append("poetry.lock: present")
    if (root / "requirements.in").exists():
        lines.append("requirements.in: present")
    if (root / "requirements.txt").exists():
        lines.append("requirements.txt: present")
    if (root / "dev-requirements.in").exists():
        lines.append("dev-requirements.in: present")
    if (root / "dev-requirements.txt").exists():
        lines.append("dev-requirements.txt: present")

    if has_poetry_project(root):
        lines.append("Detected workflow: Poetry")
    elif has_piptools_project(root):
        lines.append("Detected workflow: pip-tools")
    else:
        lines.append("Detected workflow: unknown")

    print("\n".join(lines))
    return 0


def lock_pip(root: Path) -> int:
    if not (root / "requirements.in").exists() and not (root / "dev-requirements.in").exists():
        print("No requirements.in or dev-requirements.in found.", file=sys.stderr)
        return 1

    rc = 0
    if (root / "requirements.in").exists():
        cmd = [
            sys.executable,
            "-m",
            "piptools",
            "compile",
            "--generate-hashes",
            "-o",
            "requirements.txt",
            "requirements.in",
        ]
        rc = run(cmd, cwd=root) or rc

    if (root / "dev-requirements.in").exists():
        cmd = [
            sys.executable,
            "-m",
            "piptools",
            "compile",
            "--generate-hashes",
            "-o",
            "dev-requirements.txt",
            "dev-requirements.in",
        ]
        rc = run(cmd, cwd=root) or rc

    return rc


def lock_poetry(root: Path) -> int:
    if not (root / "pyproject.toml").exists():
        print("pyproject.toml not found.", file=sys.stderr)
        return 1
    return run(["poetry", "lock"], cwd=root)


def main() -> int:
    parser = argparse.ArgumentParser(description="Manage Python dependency lock files.")
    parser.add_argument(
        "command",
        choices=["guide", "status", "lock-pip", "lock-poetry"],
        help="Action to perform.",
    )
    parser.add_argument(
        "--root",
        default=".",
        help="Project root directory to inspect or operate on.",
    )
    args = parser.parse_args()

    root = find_project_root(Path(args.root))

    if args.command == "guide":
        print(GUIDE)
        return 0
    if args.command == "status":
        return status(root)
    if args.command == "lock-pip":
        return lock_pip(root)
    if args.command == "lock-poetry":
        return lock_poetry(root)

    return 1


if __name__ == "__main__":
    raise SystemExit(main())